/* Single filter */
.element {
  filter: blur(5px);
}

/* Multiple filters (space-separated, applied left to right) */
.element {
  filter: blur(2px) brightness(1.2) contrast(150%);
}

/* No filter (reset) */
.element {
  filter: none;
}

/* Image hover effects */
.image-card img {
  transition: filter 0.3s ease;
}

.image-card:hover img {
  filter: brightness(1.1) contrast(1.2) saturate(1.1);
}

/* Grayscale to color on hover */
.grayscale-image {
  filter: grayscale(100%);
  transition: filter 0.4s ease;
}

.grayscale-image:hover {
  filter: grayscale(0%);
}

/* Blur reveal on hover */
.blur-image {
  filter: blur(8px);
  transition: filter 0.3s ease;
}

.blur-image:hover {
  filter: blur(0);
}

/* Dark mode image adjustment */
.dark-mode img {
  filter: brightness(0.8) contrast(1.1);
}

/* Loading skeleton blur effect */
.loading {
  filter: blur(10px);
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { filter: blur(10px); }
  50% { filter: blur(15px); }
}

/* drop-shadow vs box-shadow */
/* box-shadow: rectangular */
.box-shadow {
  box-shadow: 5px 5px 10px rgba(0,0,0,0.3);
}

/* drop-shadow: follows shape (PNG transparency, border-radius, clip-path) */
.drop-shadow {
  filter: drop-shadow(5px 5px 10px rgba(0,0,0,0.3));
}

/* Multiple drop shadows */
.double-shadow {
  filter: 
    drop-shadow(2px 2px 4px rgba(0,0,0,0.3))
    drop-shadow(-2px -2px 4px rgba(255,255,255,0.5));
}

/* Glowing effect with drop-shadow */
.glow {
  filter: drop-shadow(0 0 8px #00f) drop-shadow(0 0 15px #0ff);
}

/* Vintage photo effect */
.vintage {
  filter: 
    sepia(0.5) 
    contrast(1.2) 
    brightness(0.9) 
    saturate(1.1);
}

/* Cyberpunk neon effect */
.cyberpunk {
  filter: 
    brightness(1.3) 
    contrast(1.5) 
    saturate(2) 
    hue-rotate(15deg);
}

/* Dreamy soft focus */
.dreamy {
  filter: 
    blur(1px) 
    brightness(1.1) 
    saturate(1.2);
}

/* High contrast dramatic */
.dramatic {
  filter: 
    contrast(1.5) 
    brightness(0.9) 
    saturate(1.3);
}

/* Cool blue tint */
.cool-tint {
  filter: 
    hue-rotate(200deg) 
    saturate(0.8) 
    brightness(1.05);
}

/* Glassmorphism effect */
.glass-card {
  background: rgba(255, 255, 255, 0.2);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.3);
  border-radius: 16px;
}

/* Frosted sidebar */
.sidebar {
  backdrop-filter: blur(20px) brightness(0.9);
  background: rgba(0, 0, 0, 0.3);
}

/* Modal with background blur */
.modal-backdrop {
  backdrop-filter: blur(5px) grayscale(0.2);
}

/* Text readability overlay */
.image-overlay {
  background: rgba(0,0,0,0.4);
  backdrop-filter: blur(2px);
  color: white;
}

/* Vibrant background blur */
.vibrant-blur {
  backdrop-filter: blur(8px) saturate(1.8);
  background: rgba(255,255,255,0.1);
}

/* Filters trigger GPU acceleration */
.gpu-accelerated {
  filter: blur(5px);
  will-change: filter; /* Hint browser to optimize */
}

/* Animate filters efficiently */
.animated-filter {
  transition: filter 0.3s ease;
}

.animated-filter:hover {
  filter: brightness(1.2) blur(2px);
}

/* Avoid animating complex filters on large areas */
/* Bad: heavy performance */
.hero-section {
  transition: filter 0.5s ease;
}

/* Good: use transform for animations when possible */
.hero-section:hover {
  transform: scale(1.02);
  filter: brightness(1.05);
}

/* Feature detection with @supports */
.element {
  /* Fallback */
  opacity: 0.8;
}

@supports (filter: blur(5px)) {
  .element {
    filter: blur(5px);
    opacity: 1;
  }
}

/* Progressive enhancement for backdrop-filter */
.modal {
  background: rgba(0, 0, 0, 0.8); /* Fallback */
}

@supports (backdrop-filter: blur(10px)) {
  .modal {
    background: rgba(0, 0, 0, 0.3);
    backdrop-filter: blur(10px);
  }
}

.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 20px;
}

.gallery-item {
  position: relative;
  overflow: hidden;
  border-radius: 12px;
  cursor: pointer;
}

.gallery-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: filter 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Hover effects */
.gallery-item:hover img {
  filter: grayscale(0%) contrast(1.1) brightness(1.05);
}

.gallery-item:not(:hover) img {
  filter: grayscale(80%) sepia(10%);
}

/* Caption with backdrop-filter */
.caption {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 20px;
  background: rgba(0,0,0,0.5);
  backdrop-filter: blur(5px);
  color: white;
  transform: translateY(100%);
  transition: transform 0.3s ease;
}

.gallery-item:hover .caption {
  transform: translateY(0);
}

/* Respect reduced motion preferences */
@media (prefers-reduced-motion: reduce) {
  .animated-filter,
  .gallery-item img {
    transition: none;
  }

  .animated-filter:hover {
    filter: brightness(1.1); /* Subtle change only */
  }
}

/* Ensure sufficient contrast after filtering */
/* Test with tools like WebAIM contrast checker */
.text-overlay {
  background: rgba(0,0,0,0.6);
  backdrop-filter: blur(4px);
  color: white;
  /* Ensure text remains readable */
  text-shadow: 0 1px 2px rgba(0,0,0,0.3);
}

